B.a1c=new A.l(B.bO,["\u0639\u0645\u0648\u0645\u0627\u064b \u062c\u0648\u0646 \u062a\u0627 \u062c\u0648\u0644\u0627\u0626\u06cc\u061b \u06af\u0631\u0645 \u0639\u0644\u0627\u0642\u0648\u06ba \u0645\u06cc\u06ba \u06a9\u0686\u06be \u0641\u0635\u0644\u06cc\u06ba \u0645\u0626\u06cc \u06a9\u06d2 \u0622\u062e\u0631 \u0633\u06d2 \u0622\u0628\u067e\u0627\u0634\u06cc \u06a9\u06d2 \u0633\u0627\u062a\u06be \u0634\u0631\u0648\u0639 \u06c1\u0648 \u0633\u06a9\u062a\u06cc \u06c1\u06cc\u06ba\u06d4","\u0639\u0645\u0648\u0645\u0627\u064b \u0627\u06a9\u062a\u0648\u0628\u0631 \u062a\u0627 \u0646\u0648\u0645\u0628\u0631\u061b \u0679\u06be\u0646\u0688\u06d2 \u0639\u0644\u0627\u0642\u0648\u06ba \u0645\u06cc\u06ba \u06af\u0646\u062f\u0645/\u062c\u0648 \u06a9\u06cc \u0628\u0648\u0627\u0626\u06cc \u062f\u0633\u0645\u0628\u0631 \u06a9\u06d2 \u0622\u063a\u0627\u0632 \u062a\u06a9 \u0628\u0691\u06be \u0633\u06a9\u062a\u06cc \u06c1\u06d2\u06d4"],t.w)
B.a1f=new A.l(B.bO,["\u0639\u0645\u0648\u0645\u0627\u064b \u0627\u067e\u0631\u06cc\u0644 \u062a\u0627 \u062c\u0648\u0646 \u06a9\u06cc\u0648\u0646\u06a9\u06c1 \u06af\u0631\u0645\u06cc \u062c\u0644\u062f \u0634\u0631\u0648\u0639 \u06c1\u0648\u062a\u06cc \u06c1\u06d2\u061b \u0632\u06cc\u0631\u06cc\u06ba \u0633\u0646\u062f\u06be \u0645\u06cc\u06ba \u06a9\u067e\u0627\u0633/\u0686\u0627\u0648\u0644 \u06a9\u06cc \u06a9\u0627\u0634\u062a \u0639\u0645\u0648\u0645\u0627\u064b \u067e\u06c1\u0644\u06d2 \u0634\u0631\u0648\u0639 \u06c1\u0648\u062a\u06cc \u06c1\u06d2\u06d4","\u0639\u0645\u0648\u0645\u0627\u064b \u0627\u06a9\u062a\u0648\u0628\u0631 \u062a\u0627 \u062f\u0633\u0645\u0628\u0631\u061b \u0628\u0627\u0644\u0627\u0626\u06cc \u0633\u0646\u062f\u06be \u0645\u06cc\u06ba \u0646\u0645\u06cc \u06a9\u06cc \u062f\u0633\u062a\u06cc\u0627\u0628\u06cc \u067e\u0631 \u06a9\u0686\u06be \u0641\u0635\u0644\u06cc\u06ba \u062c\u0644\u062f \u0628\u06be\u06cc \u0644\u06af \u0633\u06a9\u062a\u06cc \u06c1\u06cc\u06ba\u06d4"],t.w)
